import { ErrorBoundary as ReactErrorBoundary, type ErrorProps, type ErrorResetHandler } from 'react-error-boundary';
import { useToast } from 'sonner';
import { useEffect } from 'react';

export default function ErrorBoundary({
  FallbackComponent,
  fallbackProps,
}: {
  FallbackComponent: React.ComponentType<ErrorProps & { resetErrorBoundary: ErrorResetHandler }>;
  fallbackProps?: Record<string, unknown>;
}) {
  const toast = useToast();

  useEffect(() => {
    // This effect runs after the component mounts and whenever fallbackProps change
    // We don't need to do anything here for now, but we could log errors if needed
  }, [toast, fallbackProps]);

  return (
    <ReactErrorBoundary
      FallbackComponent={FallbackComponent}
      fallbackProps={fallbackProps}
      onReset={() => {
        // Reset the error boundary state
      }}
      // You can also log the error here if needed
      onError={(error, errorInfo) => {
        console.error('Error caught by boundary:', error, errorInfo);
        // Show a toast with the error message
        toast.error('An unexpected error occurred', {
          description: error.message || 'Something went wrong',
        });
      }}
    >
      {/* The children will be wrapped by the error boundary */}
      <slot></slot>
    </ReactErrorBoundary>
  );
}

